# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
import os
import jwt
from datetime import datetime, timedelta

app = Flask(__name__)
SECRET_KEY = 'your_secret_key'

# Mock database
users = {}

@app.route('/password_reset', methods=['POST'])
def password_reset():
    email = request.json.get('email')
    
    if email not in users:
        return jsonify({'error': 'User not found'}), 404
    
    # Generate a random token
    token = jwt.encode({
        'user_email': email,
        'exp': datetime.utcnow() + timedelta(hours=1)
    }, SECRET_KEY, algorithm='HS256')
    
    reset_link = f'https://yourdomain.com/reset_password?token={token}'
    
    # Send the reset link to the user's email
    send_reset_email(email, reset_link)
    
    return jsonify({'message': 'Reset link sent successfully'})

def send_reset_email(email, reset_link):
    # Mock function to simulate sending an email
    print(f"Sending reset link to {email}: {reset_link}")

if __name__ == '__main__':
    app.run(debug=True)